class Playground {
    async run(inputs) {
        const operations = JSON.parse(inputs[0]);
        const params = JSON.parse(inputs[1]);
        const capacity = parseInt(inputs[2]);

        // internal tracking for the DLL visualization
        let order = []; // array of keys
        const cache = new Map();

        await this.cacheMap.init([]);
        await this.usageList.init([]);
        await this.stateMap.init([
            ["Capacity", capacity.toString()],
            ["Current Size", "0"],
            ["Operation", "Start"],
            ["Result", "-"]
        ]);

        this.log(`Initializing LRU Cache with capacity: ${capacity}`);
        await this.await();

        for (let i = 0; i < operations.length; i++) {
            const op = operations[i];
            const p = params[i];

            this.stateMap.put("Operation", `${op}(${p.join(', ')})`);
            this.log(`Executing ${op}(${p.join(', ')})`);
            await this.await();

            if (op === "put") {
                const key = p[0].toString();
                const val = p[1].toString();

                if (cache.has(key)) {
                    this.log(`Key ${key} exists. Updating value and moving to front.`);
                    cache.set(key, val);
                    this.cacheMap.put(key, val);
                    // Move to front
                    order = order.filter(k => k !== key);
                    order.unshift(key);
                } else {
                    if (cache.size >= capacity) {
                        const lruKey = order.pop();
                        this.log(`Capacity reached. Evicting Least Recently Used: ${lruKey}`);
                        this.usageList.highlightNode(this.usageList.getTailId(), "#ef4444");
                        await this.await();

                        cache.delete(lruKey);
                        this.cacheMap.remove(lruKey);
                        this.usageList.removeLast();
                        await this.await();
                    }

                    this.log(`Adding key ${key} to cache.`);
                    cache.set(key, val);
                    this.cacheMap.put(key, val);
                    order.unshift(key);
                }

                // Update DLL Visualizer
                await this.usageList.init(order.map(k => `[${k}:${cache.get(k)}]`));
                this.usageList.highlightNode(this.usageList.getHeadId(), "#22c55e");
                this.stateMap.put("Current Size", cache.size.toString());
                this.stateMap.put("Result", "null");
                await this.await();
                this.usageList.highlightNode(this.usageList.getHeadId(), null);

            } else if (op === "get") {
                const key = p[0].toString();
                if (cache.has(key)) {
                    const val = cache.get(key);
                    this.log(`Cache Hit! Value: ${val}. Moving ${key} to front.`);
                    this.cacheMap.highlight(key, "#22c55e");

                    // Update order
                    order = order.filter(k => k !== key);
                    order.unshift(key);

                    await this.usageList.init(order.map(k => `[${k}:${cache.get(k)}]`));
                    this.stateMap.put("Result", val);
                    await this.await();
                    this.cacheMap.highlight(key, null);
                } else {
                    this.log(`Cache Miss! Key ${key} not found.`);
                    this.stateMap.put("Result", "-1");
                    await this.await();
                }
            }
        }

        this.log("All operations completed.");
        return Array.from(cache.entries());
    }
}
